#!/usr/bin/env python3
"""
Calculate the 100th Fibonacci number using an efficient iterative algorithm.
Time: O(n), Space: O(1)
"""

def fibonacci(n):
    """Calculate the nth Fibonacci number (0-indexed: F(0)=0, F(1)=1)."""
    if n < 0:
        raise ValueError("n must be non-negative")
    if n == 0:
        return 0
    if n == 1:
        return 1

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b

if __name__ == "__main__":
    n = 100
    result = fibonacci(n)
    print(f"F({n}) = {result}")
